import math

class RAGBackbone:
    def __init__(self, chunk_size=10, dense_w=0.6, sparse_w=0.4):
        self.chunk_size = chunk_size
        self.dense_w = dense_w
        self.sparse_w = sparse_w
        self.index = []

    def _trigram_encode(self, text):
        text = text.lower()
        vec = {}
        for i in range(len(text) - 2):
            g = text[i:i+3]
            vec[g] = vec.get(g, 0) + 1
        return vec

    def _word_encode(self, text):
        words = text.lower().split()
        total = len(words)
        if total == 0:
            return {}
        freq = {}
        for w in words:
            freq[w] = freq.get(w, 0) + 1
        return {k: v / total for k, v in freq.items()}

    def _cosine(self, a, b):
        shared = set(a) & set(b)
        dot = sum(a[k] * b[k] for k in shared)
        ma = math.sqrt(sum(v**2 for v in a.values()))
        mb = math.sqrt(sum(v**2 for v in b.values()))
        return dot / (ma * mb) if ma and mb else 0.0

    def _sparse_dot(self, a, b):
        shared = set(a) & set(b)
        return sum(a[k] * b[k] for k in shared)

    def ingest(self, documents):
        for doc in documents:
            words = doc["text"].split()
            for i in range(0, len(words), self.chunk_size):
                chunk_text = " ".join(words[i:i + self.chunk_size])
                self.index.append({
                    "text": chunk_text,
                    "lang": doc.get("lang", "en"),
                    "source": doc.get("source", "unknown"),
                    "dense_vec": self._trigram_encode(chunk_text),
                    "sparse_vec": self._word_encode(chunk_text),
                })
        return len(self.index)

    def retrieve(self, query, top_k=3, threshold=0.1):
        q_d = self._trigram_encode(query)
        q_s = self._word_encode(query)
        scored = []
        for chunk in self.index:
            d_score = self._cosine(q_d, chunk["dense_vec"])
            s_score = self._sparse_dot(q_s, chunk["sparse_vec"])
            score = self.dense_w * d_score + self.sparse_w * s_score
            if score >= threshold:
                scored.append({"chunk": chunk, "score": score})
        scored.sort(key=lambda x: x["score"], reverse=True)
        return scored[:top_k]

    def assemble(self, results, word_budget=50):
        parts = []
        used = 0
        for r in results:
            line = f"[{r['chunk']['source']} | {r['chunk']['lang']}] {r['chunk']['text']}"
            wc = len(line.split())
            if used + wc > word_budget:
                break
            parts.append(line)
            used += wc
        return "\n---\n".join(parts)

